// App.jsx
import React, { useState } from 'react';
import SearchBar from './components/SearchBar';
import CityCard from './components/CityCard';
import ForecastChart from './components/ForecastChart';
import { fetchCityWeather } from './weatherApi';

export default function App() {
  const [cities, setCities] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [darkMode, setDarkMode] = useState(false);

  const handleAddCity = async (name) => {
    if (cities.length >= 5) {
      setError('Maximum 5 cities allowed.');
      return;
    }
    if (cities.find((c) => c.name.toLowerCase() === name.toLowerCase())) {
      setError(`"${name}" is already added.`);
      return;
    }

    setLoading(true);
    setError('');

    try {
      const data = await fetchCityWeather(name);
      setCities((prev) => [...prev, data]);
    } catch (e) {
      setError(e.message || 'Failed to fetch weather data.');
    } finally {
      setLoading(false);
    }
  };

  const handleRemove = (index) => {
    setCities((prev) => prev.filter((_, i) => i !== index));
  };

  const handleClearAll = () => {
    setCities([]);
    setError('');
  };

  const s = getStyles(darkMode);

  return (
    <div style={s.page}>
      <div style={s.container}>
        {/* Header */}
        <header style={s.header}>
          <div style={s.titleRow}>
            <div>
              <h1 style={s.title}>🌤 Weather Comparison</h1>
              <p style={s.subtitle}>
                Compare 5-day forecasts for up to 5 cities side by side
              </p>
            </div>
            {/* Dark mode toggle */}
            <button
              style={s.themeToggle}
              onClick={() => setDarkMode((prev) => !prev)}
              aria-label={darkMode ? 'Switch to light mode' : 'Switch to dark mode'}
              title={darkMode ? 'Light mode' : 'Dark mode'}
            >
              {darkMode ? '☀️ Light' : '🌙 Dark'}
            </button>
          </div>
        </header>

        {/* Search bar — pass darkMode so it can style itself if needed */}
        <SearchBar
          onAdd={handleAddCity}
          disabled={loading || cities.length >= 5}
          cityCount={cities.length}
          darkMode={darkMode}
        />

        {/* City pills */}
        {cities.length > 0 && (
          <div style={s.pillsRow}>
            {cities.map((c, i) => (
              <span key={i} style={s.pill}>
                {c.current?.icon} {c.name}, {c.country}
                <button
                  style={s.pillRemove}
                  onClick={() => handleRemove(i)}
                  aria-label={`Remove ${c.name}`}
                >
                  ×
                </button>
              </span>
            ))}
            <button style={s.clearBtn} onClick={handleClearAll}>
              Clear all
            </button>
          </div>
        )}

        {/* Error */}
        {error && (
          <div style={s.errorBox} role="alert">
            ⚠️ {error}
          </div>
        )}

        {/* Loading indicator */}
        {loading && (
          <div style={s.loadingBox}>
            <span style={s.spinner}>⏳</span> Fetching forecast data...
          </div>
        )}

        {/* Empty state */}
        {!loading && cities.length === 0 && !error && (
          <div style={s.emptyState}>
            <div style={s.emptyIcon}>🌍</div>
            <p style={s.emptyText}>No cities added yet</p>
            <p style={s.emptyHint}>
              Try adding: London, Tokyo, New York, Mumbai, Sydney
            </p>
          </div>
        )}

        {/* City cards grid */}
        {cities.length > 0 && (
          <div style={s.grid}>
            {cities.map((city, i) => (
              <CityCard
                key={i}
                city={city}
                index={i}
                onRemove={() => handleRemove(i)}
                darkMode={darkMode}
              />
            ))}
          </div>
        )}

        {/* Forecast chart */}
        {cities.length > 0 && <ForecastChart cities={cities} darkMode={darkMode} />}
      </div>
    </div>
  );
}

function getStyles(dark) {
  return {
    page: {
      minHeight: '100vh',
      background: dark
        ? 'linear-gradient(135deg, #0f0f1a 0%, #1a1a2e 100%)'
        : 'linear-gradient(135deg, #f0f4ff 0%, #e8f4fd 100%)',
      padding: '2rem 1rem',
      transition: 'background 0.3s ease',
    },
    container: {
      maxWidth: 1100,
      margin: '0 auto',
    },
    header: {
      marginBottom: '2rem',
    },
    titleRow: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'flex-start',
      flexWrap: 'wrap',
      gap: 12,
    },
    title: {
      fontSize: 28,
      fontWeight: 700,
      color: dark ? '#e8eaf6' : '#1a1a2e',
      marginBottom: 6,
      transition: 'color 0.3s ease',
    },
    subtitle: {
      fontSize: 15,
      color: dark ? '#9e9eb8' : '#666',
      transition: 'color 0.3s ease',
    },
    themeToggle: {
      background: dark ? '#2a2a40' : '#fff',
      border: dark ? '1px solid #3a3a55' : '1px solid #dde3ee',
      borderRadius: 20,
      padding: '6px 16px',
      fontSize: 13,
      color: dark ? '#c8caff' : '#555',
      cursor: 'pointer',
      fontWeight: 500,
      whiteSpace: 'nowrap',
      transition: 'all 0.3s ease',
    },
    pillsRow: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: 8,
      marginBottom: 20,
      alignItems: 'center',
    },
    pill: {
      display: 'flex',
      alignItems: 'center',
      gap: 6,
      background: dark ? '#2a2a40' : '#fff',
      border: dark ? '1px solid #3a3a55' : '1px solid #dde3ee',
      borderRadius: 20,
      padding: '4px 12px',
      fontSize: 13,
      color: dark ? '#c8c8e8' : '#444',
      transition: 'all 0.3s ease',
    },
    pillRemove: {
      background: 'none',
      border: 'none',
      fontSize: 16,
      color: dark ? '#6666aa' : '#aaa',
      cursor: 'pointer',
      padding: 0,
      lineHeight: 1,
    },
    clearBtn: {
      background: 'none',
      border: dark ? '1px solid #3a3a55' : '1px solid #dde3ee',
      borderRadius: 20,
      padding: '4px 14px',
      fontSize: 13,
      color: dark ? '#9999cc' : '#888',
      cursor: 'pointer',
      transition: 'all 0.3s ease',
    },
    errorBox: {
      background: dark ? '#2d1a1a' : '#fff2f2',
      border: dark ? '1px solid #5a2a2a' : '1px solid #ffcdd2',
      borderRadius: 10,
      padding: '10px 16px',
      fontSize: 14,
      color: dark ? '#ff8a80' : '#c0392b',
      marginBottom: 20,
      transition: 'all 0.3s ease',
    },
    loadingBox: {
      textAlign: 'center',
      padding: '2rem',
      color: dark ? '#9e9eb8' : '#666',
      fontSize: 15,
      transition: 'color 0.3s ease',
    },
    spinner: { fontSize: 20 },
    emptyState: {
      textAlign: 'center',
      padding: '4rem 2rem',
      color: dark ? '#6666aa' : '#888',
      transition: 'color 0.3s ease',
    },
    emptyIcon: { fontSize: 52, marginBottom: 12 },
    emptyText: {
      fontSize: 16,
      fontWeight: 600,
      marginBottom: 6,
      color: dark ? '#9999cc' : '#888',
    },
    emptyHint: {
      fontSize: 14,
      color: dark ? '#6666aa' : '#aaa',
    },
    grid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))',
      gap: 16,
      marginBottom: 8,
    },
  };
}
